+const BZ_PARAM_ERROR = -2;
+const BZ_MEM_ERROR = -3;
+const BZ_DATA_ERROR = -4;
+const BZ_DATA_ERROR_MAGIC = -5;
+const BZ_IO_ERROR = -6;
+const BZ_UNEXPECTED_EOF = -7;
